const T = true, F = false, U = 'U';
function not(x){ if (x===T) return F; if (x===F) return T; return U; }
function and(a,b){ if (a===F || b===F) return F; if (a===T && b===T) return T; return U; }
function or(a,b){ if (a===T || b===T) return T; if (a===F && b===F) return F; return U; }

// program: A = B AND C; D = NOT E; F = D OR A
