function kleeneAnd(a,b){ if(a===F||b===F) return F; if(a===U||b===U) return U; return T; }
function kleeneOr(a,b){ if(a===T||b===T) return T; if(a===U||b===U) return U; return F; }
function strongImpl(a,b){ // placeholder behavior for demonstration
  if(a===F) return T; if(a===T) return b; return (b===F?F:(b===U?U:T));
}
function parity(a,b){ // placeholder: U propagates unless forced by T/F
  if(a===F||b===F) return F; if(a===T&&b===T) return T; if(a===U||b===U) return U; return F;
